// Récupération des données
const inputData = $input.item.json;
// On fusionne avec les données fraîches de Supabase (si disponibles via un Merge précédent)
// Sinon on prend le payload du webhook
const data = inputData.body ? inputData.body : inputData;

// --- RÈGLE MÉTIER : Seul le montant compte ---
if (parseFloat(data.amount) < 6) {
  throw new Error('Montant insuffisant (< 6€) pour un reçu fiscal');
}

// --- Gestion du Numéro de Reçu ---
// Si on n'en a pas, on en génère un temporaire pour le PDF
// (Idéalement, il faudrait le sauvegarder en base ensuite)
let receiptNum = data.receipt_number;
if (!receiptNum) {
    // Génération d'un numéro de secours : REC-{ANNEE}-{FIN_UUID}
    const year = new Date().getFullYear();
    const shortId = data.transaction_id ? data.transaction_id.slice(0, 8).toUpperCase() : 'UNKNOWN';
    receiptNum = `REC-${year}-${shortId}`;
}

// --- Construction de l'objet final pour le PDF ---
return {
  transactionId: data.transaction_id || data.id, // Supporte les deux sources
  receiptNumber: receiptNum,
  amount: parseFloat(data.amount),
  paymentMethod: data.payment_method || 'carte', // Valeur par défaut si nulle
  createdAt: data.created_at || new Date().toISOString(),

  // Gestion intelligente du donateur
  // On essaie de prendre les infos les plus complètes disponibles
  donor: {
    email: data.supporter_email || data.donor_email,
    // On prend le nom complet s'il existe, sinon on assemble prénom/nom
    name: (data.supporter_name || data.donor_name || 'Donateur').trim(),
    address: data.supporter_address_line1 || data.donor_address || '',
    zip: data.supporter_postal_code || data.donor_zip || '',
    city: data.supporter_city || data.donor_city || ''
  },

  // Indicateur pour savoir si on doit mettre à jour le numéro en base plus tard
  isNewReceiptNumber: !data.receipt_number
};

// 1. Récupération des données (Fusion intelligente)
const extractedData = $('Extract & Validate Data').item.json;
const supabaseData = $input.item.json; // Les données brutes qui viennent d'arriver

// Sécurité
if (!extractedData || !extractedData.transactionId) {
  throw new Error('Données transaction manquantes');
}

// --- 2. Préparation des Variables d'Affichage ---

// NOM : On va chercher la meilleure source possible
// Supabase "supporter_name" est la plus fiable pour les calendriers
// NOM : On va chercher la meilleure source possible et on met tout EN MAJUSCULES
let rawName = supabaseData.supporter_name; 

if (!rawName || rawName.trim() === '') {
    rawName = extractedData.donor.name;
}
if (!rawName || rawName.trim() === 'Donateur') {
     rawName = extractedData.donor.email.split('@')[0];
}

// Conversion en MAJUSCULES
const donorName = (rawName || 'DONATEUR').toUpperCase(); 

// Si vide, on tente le "donor.name" construit par le nœud précédent
if (!donorName || donorName.trim() === '') {
    donorName = extractedData.donor.name;
}
// Si toujours vide, fallback (ne devrait pas arriver avec un bon backfill)
if (!donorName || donorName.trim() === 'Donateur') {
     // Tentative ultime avec email
     donorName = extractedData.donor.email.split('@')[0];
}

// ADRESSE : Idem, on consolide
const address = supabaseData.supporter_address_line1 || extractedData.donor.address || '';
const zipCity = `${supabaseData.supporter_postal_code || extractedData.donor.zip || ''} ${supabaseData.supporter_city || extractedData.donor.city || ''}`;


// CALCULS
const amount = parseFloat(extractedData.amount);
const taxReduction = (amount * 0.66).toFixed(2);
const date = new Date(extractedData.createdAt);
const formattedDate = date.toLocaleDateString('fr-FR', { year: 'numeric', month: 'long', day: 'numeric' });
const receiptNum = extractedData.receiptNumber || `REC-TEMP-${extractedData.transactionId.slice(0,8).toUpperCase()}`;


// --- 3. Construction du HTML ---
const html = `<!DOCTYPE html>
<html lang="fr">
<head>
  <meta charset="UTF-8">
  <style>
    @page { margin: 0; }

    body {
      font-family: 'Helvetica', 'Arial', sans-serif;
      margin: 0;
      padding: 30px 40px;
      color: #1f2937;
      font-size: 13px;
      line-height: 1.4;
      background: white;
    }

    .header {
      display: flex;
      align-items: center;
      justify-content: space-between;
      margin-bottom: 30px;
      border-bottom: 3px solid #b91c1c;
      padding-bottom: 15px;
    }
    .logo-container { display: flex; align-items: center; gap: 15px; }
    .logo-img { height: 75px; width: auto; }
    .org-title { font-size: 18px; font-weight: bold; color: #b91c1c; line-height: 1.2; }
    .receipt-info { text-align: right; }
    .receipt-info h1 { margin: 0; font-size: 26px; text-transform: uppercase; color: #111; }
    .receipt-number { font-size: 13px; color: #6b7280; font-weight: bold; margin-top: 5px; }

    .cerfa {
      background: #f3f4f6;
      padding: 10px 20px;
      border-radius: 6px;
      font-size: 11px;
      color: #4b5563;
      margin-bottom: 25px;
      border-left: 4px solid #b91c1c;
    }

    .grid { display: flex; gap: 30px; margin-bottom: 25px; }
    .col { flex: 1; }
    .box-title {
      font-size: 11px; text-transform: uppercase; font-weight: bold; color: #9ca3af;
      margin-bottom: 5px; border-bottom: 1px solid #e5e7eb; padding-bottom: 4px;
    }
    .box-content { font-size: 14px; }
    .box-content strong { display: block; font-size: 15px; margin-bottom: 4px; color: #111; }

    .amount-box {
      background: linear-gradient(135deg, #b91c1c 0%, #991b1b 100%);
      color: white;
      padding: 20px;
      border-radius: 12px;
      text-align: center;
      margin-bottom: 25px;
      box-shadow: 0 4px 6px -1px rgba(0, 0, 0, 0.1);
    }
    .amount-label { font-size: 14px; text-transform: uppercase; opacity: 0.9; letter-spacing: 1px; }
    .amount-value { font-size: 40px; font-weight: 800; margin: 8px 0; }
    .amount-details { font-size: 13px; opacity: 0.9; border-top: 1px solid rgba(255,255,255,0.2); display: inline-block; padding-top: 8px; margin-top: 5px; }

    .fiscal-info {
      border: 1px solid #e5e7eb; padding: 15px; border-radius: 8px; margin-bottom: 20px;
      font-size: 12px; color: #4b5563;
    }
    .fiscal-highlight { color: #b91c1c; font-weight: bold; }

    .footer-row { display: flex; justify-content: flex-end; margin-top: 5px; }
    .signature-block { text-align: center; width: 230px; }
    .location { font-size: 12px; margin-bottom: 2px; }
    .role { font-weight: bold; font-size: 13px; margin-top: 2px; border-top: 1px solid #333; padding-top: 2px; }

    .legal-footer { margin-top: 5px; text-align: center; font-size: 9px; color: #9ca3af; border-top: 1px solid #f3f4f6; padding-top: 2px; }
  </style>
</head>
<body>

  <div class="header">
    <div class="logo-container">
      <img src="https://npyfregghvnmqxwgkfea.supabase.co/storage/v1/object/public/logo/logo_amicale.png" class="logo-img" alt="Logo Amicale">
      <div class="org-title">AMICALE DES<br>SAPEURS-POMPIERS<br>DE CLERMONT</div>
    </div>
    <div class="receipt-info">
      <h1>REÇU FISCAL</h1>
      <div class="receipt-number">Réf. ${receiptNum}</div>
    </div>
  </div>

  <div class="cerfa">
    <strong>Article 200 du Code Général des Impôts</strong><br>
    Reçu au titre des dons à certains organismes d'intérêt général habilités à délivrer des reçus fiscaux.
  </div>

  <div class="grid">
    <div class="col">
      <div class="box-title">Organisme Bénéficiaire</div>
      <div class="box-content">
        <strong>Amicale SP Clermont</strong>
        Centre de Secours<br>34800 Clermont-l'Hérault<br>
        <span style="color: #666; font-size: 12px;">Association Loi 1901 - But non lucratif</span>
      </div>
    </div>
    <div class="col">
      <div class="box-title">Donateur</div>
      <div class="box-content">
        <!-- Utilisation de la variable consolidée donorName -->
        <strong>${donorName}</strong>
        ${address}<br>
        ${zipCity}<br>
        <span style="color: #666;">${extractedData.donor.email}</span>
      </div>
    </div>
  </div>

  <div class="amount-box">
    <div class="amount-label">Montant du Don</div>
    <div class="amount-value">${amount.toFixed(2)} €</div>
    <div class="amount-details">
      Reçu le ${formattedDate} &nbsp;•&nbsp; Moyen de paiement : ${
        ['card', 'carte', 'cb', 'stripe', 'carte_bancaire'].includes((extractedData.paymentMethod || '').toLowerCase()) ? 'Carte Bancaire' : 'Espèces'
      }
    </div>
  </div>

  <div class="fiscal-info">
    <p style="margin: 0 0 8px 0;">
      <!-- Phrase ajustée pour la tolérance administrative des calendriers -->
      L'Amicale certifie que ce don n'a aucune contrepartie directe ou indirecte sous forme de bien ou de prestation de services, conformément à la tolérance fiscale en vigueur pour les calendriers des Sapeurs-Pompiers.
    </p>
    <p style="margin: 0;">
      👉 Ce don ouvre droit à une réduction d'impôt de <strong>66%</strong>, soit une économie fiscale de <span class="fiscal-highlight">${taxReduction} €</span>.
      Coût réel après réduction : <strong>${(amount - parseFloat(taxReduction)).toFixed(2)} €</strong>.
    </p>
  </div>

  <div class="footer-row">
    <div class="signature-block">
      <div class="location">Fait à Clermont-l'Hérault, le ${formattedDate}</div>
      <img src="https://npyfregghvnmqxwgkfea.supabase.co/storage/v1/object/public/logo/signature_president.jpg" 
           style="height: 120px; display: block; margin: 2px auto;" 
           alt="Signature Président">
      <div class="role">Le Président</div>
    </div>
  </div>

  <div class="legal-footer">
    Document généré automatiquement via n8n - Transaction ID: ${extractedData.transactionId}
  </div>

</body>
</html>`;

return { html, transaction: extractedData };

// Récupération des données
const items = $input.all();
const htmlContent = items[0].json.html; // <--- CORRIGÉ ICI (html au lieu de htmlContent)

if (!htmlContent) {
  throw new Error('HTML manquant dans les données (vérifier la sortie du nœud précédent)');
}

// Conversion en binaire pour Gotenberg
const buffer = Buffer.from(htmlContent, 'utf8');
const base64Data = buffer.toString('base64');

return [{
  json: items[0].json, // On garde les métadonnées (transactionId, etc.)
  binary: {
    data: {
      data: base64Data,
      fileName: "index.html", // Gotenberg a besoin de ce nom spécifique
      mimeType: "text/html"
    }
  }
}];
